    'terms.updated':     { en:'Last updated: March 2026', ru:'Последнее обновление: март 2026', fa:'آخرین به‌روزرسانی: مارس ۲۰۲۶', hi:'अंतिम अपडेट: मार्च 2026', ne:'अन्तिम अपडेट: मार्च २०२६', zh:'最后更新：2026年3月' },
    'terms.t1':          { en:'1. Use of Service', ru:'1. Использование сервиса', fa:'۱. استفاده از سرویس', hi:'1. सेवा का उपयोग', ne:'१. सेवाको प्रयोग', zh:'1. 服务使用' },
    'terms.p1':          { en:'NullVPN provides private internet access. You agree to use it only for lawful purposes. The service may not be used for illegal activity, hacking, spamming, or any activity violating local laws.', ru:'NullVPN предоставляет приватный доступ в интернет. Вы соглашаетесь использовать его только в законных целях. Сервис не может использоваться для незаконной деятельности, взлома, спама или любой деятельности, нарушающей местные законы.', fa:'NullVPN دسترسی خصوصی به اینترنت ارائه می‌دهد. موافقت می‌کنید که فقط برای اهداف قانونی از آن استفاده کنید. این سرویس نمی‌تواند برای فعالیت غیرقانونی، هک، اسپم یا هر فعالیتی که قوانین محلی را نقض می‌کند استفاده شود.', hi:'NullVPN निजी इंटरनेट एक्सेस प्रदान करता है। आप इसे केवल कानूनी उद्देश्यों के लिए उपयोग करने से सहमत हैं। इस सेवा का उपयोग अवैध गतिविधि, हैकिंग, स्पैमिंग, या स्थानीय कानूनों का उल्लंघन करने वाली किसी भी गतिविधि के लिए नहीं किया जा सकता।', ne:'NullVPN निजी इन्टरनेट पहुँच प्रदान गर्छ। तपाईं यसलाई केवल कानूनी उद्देश्यहरूका लागि मात्र प्रयोग गर्न सहमत हुनुहुन्छ। सेवालाई अवैध गतिविधि, ह्याकिङ, स्प्यामिङ, वा स्थानीय कानूनहरू उल्लंघन गर्ने कुनै पनि गतिविधिका लागि प्रयोग गर्न सकिँदैन।', zh:'NullVPN提供私密互联网访问。您同意仅将其用于合法目的。不得将本服务用于非法活动、黑客攻击、垃圾邮件或任何违反当地法律的活动。' },
    'terms.t2':          { en:'2. No Logging', ru:'2. Отсутствие логирования', fa:'۲. عدم ثبت', hi:'2. कोई लॉगिंग नहीं', ne:'२. कुनै लगिङ छैन', zh:'2. 零日志' },
    'terms.p2':          { en:'NullVPN operates a strict no-logs policy. We do not collect, store, or share any information about your online activity.', ru:'NullVPN работает по строгой политике нулевого логирования. Мы не собираем, не храним и не передаём никакую информацию о вашей онлайн-активности.', fa:'NullVPN یک سیاست دقیق عدم ثبت را اجرا می‌کند. ما هیچ اطلاعاتی در مورد فعالیت آنلاین شما جمع‌آوری، ذخیره یا به اشتراک نمی‌گذاریم.', hi:'NullVPN एक सख्त नो-लॉग नीति का पालन करता है। हम आपकी ऑनलाइन गतिविधि के बारे में कोई जानकारी एकत्र, संग्रहीत या साझा नहीं करते।', ne:'NullVPN कडा नो-लग नीति सञ्चालन गर्छ। हामी तपाईंको अनलाइन गतिविधिको बारेमा कुनै जानकारी सङ्कलन, भण्डारण वा साझा गर्दैनौं।', zh:'NullVPN执行严格的零日志政策。我们不收集、存储或共享任何关于您在线活动的信息。' },
    'terms.t3':          { en:'3. Payments and Refunds', ru:'3. Платежи и возвраты', fa:'۳. پرداخت‌ها و بازپرداخت‌ها', hi:'3. भुगतान और धनवापसी', ne:'३. भुगतान र फिर्ता', zh:'3. 支付与退款' },
